import * as t from "io-ts";
import { SuiUnstakingIntent } from "./suiUnstakingIntent";

/**
 * @title Walrus Withdraw Intent
 *
 * @param {string} sharedStakingObjectId - The staking object id
 */
export const WalrusWithdrawIntent = t.intersection([
  SuiUnstakingIntent,
  t.type({
    sharedStakingObjectId: t.string,
  }),
]);

export type WalrusWithdrawIntent = t.TypeOf<typeof WalrusWithdrawIntent>;
